func lengthOfLongestSubstring(s string) int {
	if len(s) <= 1 {
        return len(s)
    }
    longest := 0
    start := 0
    records := make(map[rune]int, len(s))
    for a, i := range(s){
        if count, ok := records[i]; ok && count >= start {
            start = records[i] + 1
        }
        records[i] = a
		if (a-start+1) > longest {
			longest = a-start+1
		}
		fmt.Println(a, string(s[a]), records, longest, start)
    }
    return longest
}

